import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"巴菲特致股东信核心总结 · 2001年","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2001年/核心总结.md","filePath":"01_letters/2001年/核心总结.md"}'),r={name:"01_letters/2001年/核心总结.md"};function o(h,a,n,d,u,s){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="巴菲特致股东信核心总结-·-2001年" tabindex="-1">巴菲特致股东信核心总结 · 2001年 <a class="header-anchor" href="#巴菲特致股东信核心总结-·-2001年" aria-label="Permalink to &quot;巴菲特致股东信核心总结 · 2001年&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净值亏损37.7亿美元，每股账面价值下降6.2%</li><li>过去37年每股账面价值年复合增长率22.6%</li><li>相对结果与标普500持平（均下跌11.9%）</li></ul><h2 id="重大事件-9·11恐怖袭击" tabindex="-1">重大事件：9·11恐怖袭击 <a class="header-anchor" href="#重大事件-9·11恐怖袭击" aria-label="Permalink to &quot;重大事件：9·11恐怖袭击&quot;">​</a></h2><h3 id="教训与错误" tabindex="-1">教训与错误 <a class="header-anchor" href="#教训与错误" aria-label="Permalink to &quot;教训与错误&quot;">​</a></h3><ul><li>违反&quot;诺亚法则&quot;：预测下雨不算数，建造方舟才算数</li><li>通用再保险在承保时未设置应有的保护措施</li><li>忽视了大规模恐怖主义损失的可能性</li></ul><h3 id="保险业根本错误" tabindex="-1">保险业根本错误 <a class="header-anchor" href="#保险业根本错误" aria-label="Permalink to &quot;保险业根本错误&quot;">​</a></h3><ul><li>关注经验而非风险敞口</li><li>承担巨大恐怖主义风险却未获得任何保费</li><li>保险业整体可能因超级灾难而破产</li></ul><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="已完成" tabindex="-1">已完成 <a class="header-anchor" href="#已完成" aria-label="Permalink to &quot;已完成&quot;">​</a></h3><ol><li><strong>MiTek</strong> - 屋顶桁架连接板世界领先生产商</li><li><strong>XTRA</strong> - 卡车拖车租赁商</li><li><strong>Larson-Juhl</strong> - 美国定制画框领导者</li><li><strong>Fruit of the Loom</strong> - 破产收购，内衣制造商</li></ol><h3 id="收购特点" tabindex="-1">收购特点 <a class="header-anchor" href="#收购特点" aria-label="Permalink to &quot;收购特点&quot;">​</a></h3><ul><li>全部现金支付</li><li>55名MiTek团队成员每人至少投入10万美元购买公司10%股份</li><li>真正的所有者心态，非期权持有者</li></ul><h2 id="保险承保三原则" tabindex="-1">保险承保三原则 <a class="header-anchor" href="#保险承保三原则" aria-label="Permalink to &quot;保险承保三原则&quot;">​</a></h2><h3 id="优质保险公司的三个关键原则" tabindex="-1">优质保险公司的三个关键原则 <a class="header-anchor" href="#优质保险公司的三个关键原则" aria-label="Permalink to &quot;优质保险公司的三个关键原则&quot;">​</a></h3><ol><li><strong>只接受能够正确评估的风险</strong> - 在能力圈内，忽略市场份额</li><li><strong>限制业务以避免损失聚集</strong> - 不让单一事件威胁偿付能力</li><li><strong>避免涉及道德风险的业务</strong> - 与坏人签好合同是不可能的</li></ol><h3 id="通用再保险的失败" tabindex="-1">通用再保险的失败 <a class="header-anchor" href="#通用再保险的失败" aria-label="Permalink to &quot;通用再保险的失败&quot;">​</a></h3><ul><li>准备金严重不足（8亿美元错误）</li><li>导致激励薪酬过度支付和所得税提前缴纳</li><li>乔·布兰登9月被任命为CEO，开始恢复承保纪律</li></ul><h2 id="保险业务表现" tabindex="-1">保险业务表现 <a class="header-anchor" href="#保险业务表现" aria-label="Permalink to &quot;保险业务表现&quot;">​</a></h2><h3 id="浮存金与成本" tabindex="-1">浮存金与成本 <a class="header-anchor" href="#浮存金与成本" aria-label="Permalink to &quot;浮存金与成本&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>浮存金（百万美元）</th></tr></thead><tbody><tr><td>1997</td><td>7,386</td></tr><tr><td>2000</td><td>27,871</td></tr><tr><td>2001</td><td>35,508</td></tr></tbody></table><ul><li>2001年浮存金成本高达12.8%（因9·11损失）</li><li>阿吉特·贾恩的再保险部门贡献134亿美元浮存金</li></ul><h3 id="盖可保险" tabindex="-1">盖可保险 <a class="header-anchor" href="#盖可保险" aria-label="Permalink to &quot;盖可保险&quot;">​</a></h3><ul><li>保费增长6.6%，浮存金增长3.08亿美元</li><li>承保利润2.21亿美元</li><li>有效保单数下降0.8%（优选客户增长1.6%，标准/非标准下降10.1%）</li></ul><h2 id="损失准备金会计" tabindex="-1">损失准备金会计 <a class="header-anchor" href="#损失准备金会计" aria-label="Permalink to &quot;损失准备金会计&quot;">​</a></h2><h3 id="术语批评" tabindex="-1">术语批评 <a class="header-anchor" href="#术语批评" aria-label="Permalink to &quot;术语批评&quot;">​</a></h3><ul><li>&quot;损失发展&quot;是误导性术语</li><li>应称为&quot;发生时未能确认的损失成本&quot;</li><li>准备金不足是行业普遍问题</li></ul><h3 id="准备金困境" tabindex="-1">准备金困境 <a class="header-anchor" href="#准备金困境" aria-label="Permalink to &quot;准备金困境&quot;">​</a></h3><ul><li>保险公司自己评分的考试</li><li>财务困难公司很少严格评分</li><li>历史运营中埋藏许多&quot;租来的西装&quot;</li></ul><h2 id="非保险业务亮点" tabindex="-1">非保险业务亮点 <a class="header-anchor" href="#非保险业务亮点" aria-label="Permalink to &quot;非保险业务亮点&quot;">​</a></h2><h3 id="鞋类业务" tabindex="-1">鞋类业务 <a class="header-anchor" href="#鞋类业务" aria-label="Permalink to &quot;鞋类业务&quot;">​</a></h3><ul><li>税前亏损4,620万美元</li><li>Dexter错误承认：收购价过高、用股票支付、拖延运营变革</li><li>德克斯特置于H.H. Brown管理之下</li></ul><h3 id="中美能源" tabindex="-1">中美能源 <a class="header-anchor" href="#中美能源" aria-label="Permalink to &quot;中美能源&quot;">​</a></h3><ul><li>英国约克郡电力收购，服务360万客户</li><li>全国第二大住宅房地产经纪业务（10.6万笔交易）</li></ul><h3 id="飞行服务" tabindex="-1">飞行服务 <a class="header-anchor" href="#飞行服务" aria-label="Permalink to &quot;飞行服务&quot;">​</a></h3><ul><li>FlightSafety投资2.58亿美元购买模拟器</li><li>NetJets欧洲亏损抵消美国利润</li></ul><h2 id="投资组合" tabindex="-1">投资组合 <a class="header-anchor" href="#投资组合" aria-label="Permalink to &quot;投资组合&quot;">​</a></h2><p>主要持仓：</p><ul><li>可口可乐：94.3亿美元</li><li>美国运通：54.1亿美元</li><li>吉列：32.06亿美元</li><li>富国银行：23.15亿美元</li></ul><h2 id="垃圾债券投资" tabindex="-1">垃圾债券投资 <a class="header-anchor" href="#垃圾债券投资" aria-label="Permalink to &quot;垃圾债券投资&quot;">​</a></h2><h3 id="经验与原则" tabindex="-1">经验与原则 <a class="header-anchor" href="#经验与原则" aria-label="Permalink to &quot;经验与原则&quot;">​</a></h3><ul><li>50年经验证明有回报</li><li>从不购买新发行的垃圾债券</li><li>华盛顿公共电力系统、克莱斯勒金融、德士古、RJR纳贝斯克等成功案例</li></ul><h3 id="finova交易" tabindex="-1">FINOVA交易 <a class="header-anchor" href="#finova交易" aria-label="Permalink to &quot;FINOVA交易&quot;">​</a></h3><ul><li>与Leucadia合作组建Berkadia</li><li>借款56亿美元资助破产计划</li><li>购买最多5亿美元新发行债券</li></ul><h2 id="管理原则" tabindex="-1">管理原则 <a class="header-anchor" href="#管理原则" aria-label="Permalink to &quot;管理原则&quot;">​</a></h2><h3 id="《基本原则》-1956年" tabindex="-1">《基本原则》（1956年） <a class="header-anchor" href="#《基本原则》-1956年" aria-label="Permalink to &quot;《基本原则》（1956年）&quot;">​</a></h3><ul><li>以证券市场整体表现衡量业绩</li><li>不能承诺结果</li><li>管理者与股东利益一致</li></ul><h3 id="ceo责任" tabindex="-1">CEO责任 <a class="header-anchor" href="#ceo责任" aria-label="Permalink to &quot;CEO责任&quot;">​</a></h3><ul><li>批评许多CEO一边敦促投资者买入股票一边抛售</li><li>视股东为伙伴而非待宰肥羊</li><li>&quot;我可以为你做任何事&quot;——&quot;重新定价我的期权&quot;</li></ul><h2 id="其他要点" tabindex="-1">其他要点 <a class="header-anchor" href="#其他要点" aria-label="Permalink to &quot;其他要点&quot;">​</a></h2><ul><li>总部员工14.8人，管理110,000名员工</li><li>员工总数增加约40,000人</li><li>本杰明·格雷厄姆的影响：从1951年开始，表现显著改善</li></ul><hr><p><em>核心要点总结完成</em></p>',53)])])}const b=l(r,[["render",o]]);export{q as __pageData,b as default};
